def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a phrase (without subject) for a single triple
    def _phrase(p: str, o: str) -> str:
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"serves the city of {o}"
        if p == "location":
            return f"is located in {o}"
        if p == "country":
            return f"is in {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"is operated by {o}"
        if p == "runwaySurfaceType":
            return f"has a runway surface of {o}"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{idx.lower()} runway is {o} metres long"
        # Runway identifiers
        if p == "runwayName":
            return f"runway is named {o}"
        if p == "runwayLength":
            return f"runway length is {o}"
        # Runway surface types
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            return f"{idx.lower()} runway surface is {o}"
        # Runway numbers
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            return f"{idx.lower()} runway number is {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"has ICAO code {o}"
        if p == "locationIdentifier":
            return f"has location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"is owned by {o}"
        if p == "largestCity":
            return f"has the largest city {o}"
        if p == "capital":
            return f"has capital {o}"
        if p == "language" or p == "officialLanguage":
            return f"has official language {o}"
        if p == "leader":
            return f"has leader {o}"
        if p == "leaderTitle":
            return f"has leader title {o}"
        if p == "leaderParty":
            return f"has leader belonging to the {o} party"
        # Native name
        if p == "nativeName":
            return f"is known as {o}"
        # Administrative info
        if p == "administrativeArrondissement":
            return f"is in the administrative arrondissement of {o}"
        if p == "mayor":
            return f"has mayor {o}"
        if p == "currency":
            return f"uses the {o}"
        if p == "demonym":
            return f"people are called {o}"
        if p == "regionServed":
            return f"serves the {o} region"
        if p == "hubAirport":
            return f"is a hub airport for {o}"
        if p == "headquarter":
            return f"has its headquarters at {o}"
        if p == "foundedBy":
            return f"was founded by {o}"
        if p == "foundingYear":
            return f"was founded in {o}"
        if p == "postalCode":
            return f"has postal code {o}"
        if p == "areaCode":
            return f"has area code {o}"
        if p == "ceremonialCounty":
            return f"is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"has county seat {o}"
        if p == "chief":
            return f"has chief {o}"
        if p == "jurisdiction":
            return f"has jurisdiction over {o}"
        if p == "city":
            return f"is located in {o}"
        # Fallback for any other predicate
        return f"has {p} {o}"

    # Group phrases by subject to avoid repetitive subject mentions
    from collections import OrderedDict
    subject_map: "OrderedDict[str, list[str]]" = OrderedDict()
    for t in triples:
        subj = t.subject
        phrase = _phrase(t.predicate, _clean(t.object))
        subject_map.setdefault(subj, []).append(phrase)

    # Build a clause for each subject
    subject_clauses: list[str] = []
    for subj, parts in subject_map.items():
        if len(parts) == 1:
            clause = f"{subj} {parts[0]}"
        else:
            # combine parts with commas and a final 'and'
            clause = f"{subj}, " + ", ".join(parts[:-1]) + ", and " + parts[-1]
        subject_clauses.append(clause)

    # Combine all subject clauses into a single sentence
    if not subject_clauses:
        return ""
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    else:
        sentence = "; ".join(subject_clauses[:-1]) + ", and " + subject

    # Build clauses
    clauses: list[str] = [_clause(t.subject, t.predicate, _clean(t.object)) for t in triples]

    # Combine clauses into a single fluent sentence
    if not clauses:
        return ""
    # Lower‑case all clauses except the first for natural flow
    formatted = [clauses[0]] + [c[0].lower() + c[1:] if c else c for c in clauses[1:]]
    if len(formatted) == 1:
        sentence = formatted[0] + "."
    else:
        sentence = ", ".join(formatted[:-1]) + ", and " + formatted[-1] + "."
    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

